// Test for the exclude-newer precedence issue
#[cfg(test)]
mod test {
    use pixi_manifest::{FeaturesExt, HasFeaturesIter, HasWorkspaceManifest, WorkspaceManifest};
    use pixi_manifest::manifests::workspace::parse_pixi_toml;
    use pixi_spec::ExcludeNewer;
    use rattler_conda_types::PackageName;
    use std::str::FromStr;

    #[test]
    fn test_url_channel_exclude_newer_override() {
        // Scenario: url channel has exclude-newer=2d, workspace has exclude-newer=1y
        // Expected: channel-level should take precedence for that channel

        struct TestFeatures<'a> {
            manifest: &'a WorkspaceManifest,
            features: Vec<&'a pixi_manifest::Feature>,
        }

        impl<'a> HasWorkspaceManifest<'a> for TestFeatures<'a> {
            fn workspace_manifest(&self) -> &'a WorkspaceManifest {
                self.manifest
            }
        }

        impl<'a> HasFeaturesIter<'a> for TestFeatures<'a> {
            fn features(&self) -> impl DoubleEndedIterator<Item = &'a pixi_manifest::Feature> + 'a {
                self.features.clone().into_iter()
            }
        }

        let contents = r#"
[project]
name = "foo"
channels = ["conda-forge", { channel = "https://prefix.dev/github-releases", exclude-newer = "0d" }]
platforms = []
exclude-newer = "2015-12-02T02:07:43Z"
"#;

        let before = chrono::Utc::now();
        let manifest = parse_pixi_toml(contents).manifest;
        let default_feature = manifest.default_feature();
        let features = TestFeatures {
            manifest: &manifest,
            features: vec![default_feature],
        };
        let config = features.exclude_newer_config().unwrap().unwrap();
        let after = chrono::Utc::now();

        let package = PackageName::from_str("polars").unwrap();

        // For the URL channel, the channel-level 0d should take precedence
        let url_channel_cutoff = config.cutoff_for_package(&package, Some("https://prefix.dev/github-releases"));
        println!("url_channel_cutoff: {:?}", url_channel_cutoff);
        println!("before: {:?}", before);
        println!("after: {:?}", after);
        assert!(url_channel_cutoff >= before, "URL channel cutoff should be recent (0d), got: {:?}", url_channel_cutoff);
        assert!(url_channel_cutoff <= after + chrono::Duration::seconds(1));

        // For conda-forge, workspace level should still apply
        let forge_cutoff = config.cutoff_for_package(&package, Some("conda-forge"));
        assert_eq!(
            forge_cutoff,
            chrono::DateTime::parse_from_rfc3339("2015-12-02T02:07:43Z")
                .unwrap()
                .with_timezone(&chrono::Utc)
        );
    }
}
