                    priority: None,
                    exclude_newer: None,
                },
                &PrioritizedChannel {
                    channel: NamedChannelOrUrl::Name(String::from("nvidia")),
                    priority: Some(-1),
                    exclude_newer: None,
                },
            ]
        );
        assert_eq!(
